/**
 * Seed script for the demo-bank tenant.
 *
 * Upserts the tenant from kb/demo-bank/_config.yaml and inserts sample KB
 * chunks in all three languages with placeholder embeddings.
 *
 * Placeholder embeddings (all 0.1) have no semantic meaning — cosine ranking
 * will be uniform until real embeddings are generated by the ingestion pipeline.
 * The chunks are still returned by keyword scoring and appear in the prompt.
 *
 * Usage:
 *   npx tsx scripts/seed-demo.ts
 *   # or via npm script:
 *   npm run seed:demo
 */

import { configDotenv } from 'dotenv';
configDotenv({ path: new URL('../apps/backend/.env', import.meta.url) });

import { readFile } from 'node:fs/promises';
import { join, dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { createHash } from 'node:crypto';
import { parse as parseYaml } from 'yaml';
import { Pool } from 'pg';

const here = dirname(fileURLToPath(import.meta.url));
const root = resolve(here, '..');

const TENANT_ID = 'demo-bank';
const PLACEHOLDER_EMBEDDING = `[${Array(1536).fill(0.1).join(',')}]`;

// ── Tenant config ──────────────────────────────────────────────────────────

interface TenantConfigYaml {
  name: string;
  allowedOrigins: string[];
  config: Record<string, unknown>;
}

async function syncTenant(pool: Pool): Promise<void> {
  const configPath = join(root, 'kb', TENANT_ID, '_config.yaml');
  const yaml = await readFile(configPath, 'utf8');
  const parsed = parseYaml(yaml) as TenantConfigYaml;

  await pool.query(
    `INSERT INTO tenants (id, name, allowed_origins, config)
       VALUES ($1, $2, $3::text[], $4::jsonb)
     ON CONFLICT (id) DO UPDATE
       SET name            = EXCLUDED.name,
           allowed_origins = EXCLUDED.allowed_origins,
           config          = EXCLUDED.config,
           updated_at      = now()`,
    [TENANT_ID, parsed.name, parsed.allowedOrigins, JSON.stringify(parsed.config)],
  );
  console.log(`✓ tenant "${TENANT_ID}" synced`);
}

