async function upsertChunks(pool: Pool): Promise<void> {
  let upserted = 0;
  for (const chunk of CHUNKS) {
    const hash = createHash('sha256')
      .update(`${TENANT_ID}:${chunk.chunk_id}:${chunk.content}`)
      .digest('hex')
      .slice(0, 16);

    await pool.query(
      `INSERT INTO kb_chunks
         (tenant_id, lang, source_file, chunk_id, category, title, content, embedding, tokens, content_hash)
       VALUES ($1, $2, $3, $4, $5, $6, $7, $8::vector, $9, $10)
       ON CONFLICT (tenant_id, lang, chunk_id) DO UPDATE
         SET title        = EXCLUDED.title,
             content      = EXCLUDED.content,
             embedding    = EXCLUDED.embedding,
             tokens       = EXCLUDED.tokens,
             content_hash = EXCLUDED.content_hash,
             updated_at   = now()`,
      [
        TENANT_ID,
        chunk.lang,
        chunk.source_file,
        chunk.chunk_id,
        chunk.category,
        chunk.title,
        chunk.content,
        PLACEHOLDER_EMBEDDING,
        Math.ceil(chunk.content.length / 4), // rough token estimate
        hash,
      ],
    );
    upserted++;
  }
  console.log(`✓ ${upserted} KB chunks upserted (placeholder embeddings)`);
  console.log('  ℹ  Run the ingestion pipeline to replace placeholders with real embeddings.');
}

// ── Main ───────────────────────────────────────────────────────────────────

async function main(): Promise<void> {
  const pool = new Pool({
    connectionString: process.env.DATABASE_URL ?? 'postgres://chatbot:chatbot@localhost:5433/chatbot',
  });

  try {
    await syncTenant(pool);
    await upsertChunks(pool);
    console.log(`\n✓ Demo seed complete. Start the server and try:\n`);
    console.log(`  # Create a session`);
    console.log(`  curl -X POST http://localhost:3000/api/session/new \\`);
    console.log(`    -H "Origin: http://localhost:3000" \\`);
    console.log(`    -H "Content-Type: application/json" \\`);
    console.log(`    -d '{"tenant_id":"demo-bank"}'`);
  } finally {
    await pool.end();
  }
}

main().catch((err: unknown) => {
  console.error(err instanceof Error ? err.message : err);
  process.exit(1);
});
